const QUERY_TYPES = {
  match: (field, value, options = {}) => ({
    match: {
      [field]: {
        query: value,
        ...(options.operator && { operator: options.operator }),
        ...(options.fuzziness && { fuzziness: options.fuzziness }),
        ...(options.analyzer && { analyzer: options.analyzer })
      }
    }
  }),

  multi_match: (fields, value, options = {}) => ({
    multi_match: {
      query: value,
      fields: fields,
      type: options.type || 'best_fields',
      ...(options.operator && { operator: options.operator }),
      ...(options.fuzziness && { fuzziness: options.fuzziness }),
      ...(options.tie_breaker && { tie_breaker: options.tie_breaker })
    }
  }),

  term: (field, value) => ({
    term: { [field]: value }
  }),

  terms: (field, values) => ({
    terms: { [field]: values }
  }),

  range: (field, conditions) => ({
    range: { [field]: conditions }
  }),

  exists: (field) => ({
    exists: { field }
  }),

  prefix: (field, value) => ({
    prefix: { [field]: { value } }
  }),

  wildcard: (field, value) => ({
    wildcard: { [field]: { value } }
  }),

  phrase: (field, value, options = {}) => ({
    match_phrase: {
      [field]: {
        query: value,
        ...(options.slop && { slop: options.slop })
      }
    }
  }),

  nested: (path, query) => ({
    nested: { path, query }
  })
};

