// ============================================================
// QUERY BUILDER
// ============================================================

class ElasticsearchQueryBuilder {
  constructor(searchRequest) {
    this.request = searchRequest;
    this.body = {};
  }

  build() {
    this._buildBaseQuery();
    this._applyFilters();
    this._applyScoringFunctions();
    this._applyPagination();
    this._applySort();
    this._applyHighlight();
    this._applyAggregations();
    this._applySourceFiltering();

    return {
      index: this.request.index,
      body: this.body
    };
  }

  _buildBaseQuery() {
    const queryConfig = this.request.query;

    if (queryConfig && queryConfig.text) {
      if (queryConfig.fields && queryConfig.fields.length > 1) {
        this.baseQuery = QUERY_TYPES.multi_match(
          queryConfig.fields,
          queryConfig.text,
          {
            type: queryConfig.type,
            operator: queryConfig.operator,
            fuzziness: queryConfig.fuzziness,
            tie_breaker: queryConfig.tie_breaker
          }
        );
      } else if (queryConfig.fields && queryConfig.fields.length === 1) {
        this.baseQuery = QUERY_TYPES.match(
          queryConfig.fields[0],
          queryConfig.text,
          {
            operator: queryConfig.operator,
            fuzziness: queryConfig.fuzziness
          }
        );
      } else {
        this.baseQuery = QUERY_TYPES.multi_match(
          ['*'],
          queryConfig.text,
          {
            type: queryConfig.type,
            operator: queryConfig.operator
          }
        );
      }
    } else {
      this.baseQuery = { match_all: {} };
    }
  }

  _buildFilter(filterDef) {
    switch (filterDef.type) {
      case 'term':
        return QUERY_TYPES.term(filterDef.field, filterDef.value);
      case 'terms':
        return QUERY_TYPES.terms(filterDef.field, filterDef.value);
      case 'range':
        return QUERY_TYPES.range(filterDef.field, filterDef.value);
      case 'exists':
        return QUERY_TYPES.exists(filterDef.field);
      case 'prefix':
        return QUERY_TYPES.prefix(filterDef.field, filterDef.value);
      case 'wildcard':
        return QUERY_TYPES.wildcard(filterDef.field, filterDef.value);
      case 'nested':
        if (filterDef.nested_path && filterDef.nested_query) {
          return QUERY_TYPES.nested(
            filterDef.nested_path,
            this._buildFilter(filterDef.nested_query)
          );
        }
        throw new Error(`Nested filter requires nested_path and nested_query`);
      default:
        throw new Error(`Unknown filter type: ${filterDef.type}`);
    }
  }

  _applyFilters() {
    const filters = this.request.filters;
    if (!filters) {
      this.filteredQuery = this.baseQuery;
      return;
    }

    const boolQuery = {
      bool: {
        must: [this.baseQuery]
      }
    };

    if (filters.must && filters.must.length > 0) {
      boolQuery.bool.filter = filters.must.map(f => this._buildFilter(f));
    }

    if (filters.must_not && filters.must_not.length > 0) {
      boolQuery.bool.must_not = filters.must_not.map(f => this._buildFilter(f));
    }

    if (filters.should && filters.should.length > 0) {
      boolQuery.bool.should = filters.should.map(f => this._buildFilter(f));
      if (filters.minimum_should_match !== undefined) {
        boolQuery.bool.minimum_should_match = filters.minimum_should_match;
      }
    }

    this.filteredQuery = boolQuery;
  }

  _applyScoringFunctions() {
    const scoring = this.request.scoring;
    if (!scoring || !scoring.functions || scoring.functions.length === 0) {
      this.body.query = this.filteredQuery;
      return;
    }

    const functions = [];

    for (const funcDef of scoring.functions) {
      const scoringFunction = SCORING_FUNCTIONS[funcDef.name];
      if (!scoringFunction) {
        throw new Error(`Unknown scoring function: ${funcDef.name}`);
      }

      // Validate parameters against the function's specific schema
      const { error, value: validatedParams } = scoringFunction.paramSchema.validate(funcDef.params, {
        abortEarly: false,
        stripUnknown: true
      });

      if (error) {
        throw new Error(`Invalid parameters for scoring function '${funcDef.name}': ${error.message}`);
      }

      const built = scoringFunction.buildFunctionScore(validatedParams);

      if (scoringFunction.isMultiple && Array.isArray(built)) {
        functions.push(...built);
      } else {
        functions.push(built);
      }
    }

    this.body.query = {
      function_score: {
        query: this.filteredQuery,
        functions: functions,
        score_mode: scoring.score_mode || 'sum',
        boost_mode: scoring.boost_mode || 'multiply',
        max_boost: scoring.max_boost || 100
      }
    };

    if (scoring.min_score !== undefined) {
      this.body.min_score = scoring.min_score;
    }
  }

  _applyPagination() {
    const pagination = this.request.pagination || {};
    this.body.from = pagination.from || 0;
    this.body.size = pagination.size || 10;
  }

  _applySort() {
    if (!this.request.sort || this.request.sort.length === 0) return;

    this.body.sort = this.request.sort.map(s => {
      const sortObj = {
        [s.field]: {
          order: s.order || 'desc'
        }
      };
      if (s.mode) sortObj[s.field].mode = s.mode;
      if (s.missing !== undefined) sortObj[s.field].missing = s.missing;
      return sortObj;
    });
  }

  _applyHighlight() {
    if (!this.request.highlight) return;

    const hlConfig = this.request.highlight;
    const fields = {};
    for (const field of hlConfig.fields) {
      fields[field] = {};
    }

    this.body.highlight = {
      fields: fields,
      pre_tags: [hlConfig.pre_tag || '<em>'],
      post_tags: [hlConfig.post_tag || '</em>'],
      fragment_size: hlConfig.fragment_size || 150,
      number_of_fragments: hlConfig.number_of_fragments || 3
    };
  }

  _applyAggregations() {
    if (!this.request.aggregations || this.request.aggregations.length === 0) return;

    const aggs = {};
    for (const aggDef of this.request.aggregations) {
      const aggBody = { field: aggDef.field };
      const options = aggDef.options || {};

      switch (aggDef.type) {
        case 'terms':
          aggBody.size = options.size || 10;
          if (options.min_doc_count !== undefined) aggBody.min_doc_count = options.min_doc_count;
          if (options.order) aggBody.order = options.order;
          break;
        case 'histogram':
          aggBody.interval = options.interval;
          if (options.min_doc_count !== undefined) aggBody.min_doc_count = options.min_doc_count;
          break;
        case 'date_histogram':
          if (options.calendar_interval) aggBody.calendar_interval = options.calendar_interval;
          else if (options.fixed_interval) aggBody.fixed_interval = options.fixed_interval;
          if (options.min_doc_count !== undefined) aggBody.min_doc_count = options.min_doc_count;
          break;
        case 'range':
          aggBody.ranges = options.ranges;
          break;
        // avg, sum, min, max, cardinality, stats just need the field
      }

      aggs[aggDef.name] = { [aggDef.type]: aggBody };
    }

    this.body.aggs = aggs;
  }

  _applySourceFiltering() {
    if (this.request.source !== undefined) {
      this.body._source = this.request.source;
    }
  }
}

