// List available scoring functions
app.get('/api/scoring-functions', (req, res) => {
  const functions = {};
  for (const [name, func] of Object.entries(SCORING_FUNCTIONS)) {
    functions[name] = {
      description: func.description,
      parameters: func.paramSchema.describe()
    };
  }
  res.json({ scoring_functions: functions });
});

// Main search endpoint
app.post('/api/search', async (req, res) => {
  try {
    // Validate the entire request
    const { error, value: validatedRequest } = searchRequestSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => ({
          message: d.message,
          path: d.path.join('.')
        }))
      });
    }

    // Build the query
    const builder = new ElasticsearchQueryBuilder(validatedRequest);
    const esQuery = builder.build();

    console.log('Executing ES query:', JSON.stringify(esQuery, null, 2));

    // Execute the query
    const result = await esClient.search(esQuery);

    // Format response
    const response = {
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map(hit => ({
        id: hit._id,
        index: hit._index,
        score: hit._score,
        source: hit._source,
        highlight: hit.highlight || undefined,
        sort: hit.sort || undefined
      })),
      aggregations: result.aggregations || undefined,
      took: result.took
    };

    res.json(response);
  } catch (err) {
    console.error('Search error:', err);

    if (err.meta && err.meta.body) {
      return res.status(err.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        details: err.meta.body.error
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: err.message
    });
  }
});

